import React, { useState, useRef, useEffect } from "react";
import "./ChatbotV2.css";

const ChatbotV2 = () => {
  const [messages, setMessages] = useState([
    {
      text: "Hello! I'm your AI Data Assistant. Ask me anything!",
      sender: "bot",
      timestamp: new Date()
    }
  ]);

  const [customQuery, setCustomQuery] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);

  const messagesContainerRef = useRef(null);

  // ================= SCROLL =================
  useEffect(() => {
    if (messagesContainerRef.current) {
      messagesContainerRef.current.scrollTop =
        messagesContainerRef.current.scrollHeight;
    }
  }, [messages]);

  // ================= MIC (WORKING VERSION) =================
  const toggleMic = () => {
    const SpeechRecognition =
      window.SpeechRecognition || window.webkitSpeechRecognition;

    if (!SpeechRecognition) {
      alert("Speech recognition not supported. Please use Chrome.");
      return;
    }

    try {
      const recognition = new SpeechRecognition();
      recognition.lang = "en-US";
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onresult = (event) => {
        const transcript = event.results[0][0].transcript;
        setCustomQuery(transcript);
      };

      recognition.onerror = (event) => {
        console.error("Speech error:", event.error);
        alert("Microphone access blocked. Please allow microphone permission.");
      };

      recognition.start(); // 🔥 MUST BE inside click
    } catch (err) {
      console.error(err);
    }
  };

  // ================= SEND QUERY =================
  const handleCustomQuery = () => {
    if (!customQuery.trim()) return;

    const userMessage = {
      text: customQuery,
      sender: "user",
      timestamp: new Date()
    };

    setMessages((prev) => [...prev, userMessage]);
    setCustomQuery("");
    setIsProcessing(true);

    // Fake bot response (replace with API)
    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        {
          text: "Got it! This is a demo response.",
          sender: "bot",
          timestamp: new Date()
        }
      ]);
      setIsProcessing(false);
    }, 1200);
  };

  return (
    <div className="chatbot-v2-container">
      {/* HEADER */}
      <div className="chatbot-v2-header">
        <h2>Viola Communications</h2>
      </div>

      {/* CHAT AREA */}
      <div className="messages-container" ref={messagesContainerRef}>
        {messages.map((msg, i) => (
          <div key={i} className={`message ${msg.sender}`}>
            {msg.text}
          </div>
        ))}
      </div>

      {/* INPUT */}
      <div className="custom-input-section">
        <div className="textarea-wrapper">
          <textarea
            value={customQuery}
            onChange={(e) => setCustomQuery(e.target.value)}
            placeholder="Type your question here..."
            disabled={isProcessing}
          />

          <button
            type="button"
            className="mic-inside"
            onClick={toggleMic}
            disabled={isProcessing}
            title="Speak"
          >
            🎤
          </button>
        </div>

        <button
          className="ask-btn"
          onClick={handleCustomQuery}
          disabled={isProcessing}
        >
          Ask Question
        </button>
      </div>
    </div>
  );
};

export default ChatbotV2;
